1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_RATE = 0.1;
5	const CURSED_SURCHARGE_RATE = 0.5;
6	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
7	const HIGH_ENCHANTMENT_THRESHOLD = 5;
8	
9	const MAIN_ITEM_BASE_PREMIUM_BY_TYPE: Record<string, number> = {
10	  sword: 100,
11	  amulet: 60,
12	  staff: 80,
13	  potion: 40,
14	};
15	
16	const COMPONENT_TYPES = new Set<string>(["rune", "moonstone"]);
17	const COMPONENT_BASE_PREMIUM = 25;
18	const COMPONENT_BLOCK_PREMIUM = 60;
19	
20	export type Customer = {
21	  yearsInsured: number;
22	  previousQuotes: number;
23	};
24	
25	export type Item = {
26	  type: string;
27	  material?: string;
28	  enchantment?: number;
29	  cursed?: boolean;
30	};
31	
32	export type QuoteInput = {
33	  items: Item[];
34	  customer: Customer;
35	};
36	
37	const BLOCK_SIZE = 3;
38	
39	const formsOneBlock = (count: number): boolean => {
40	  if (count < BLOCK_SIZE) return false;
41	  const leftover = count - BLOCK_SIZE;
42	  return leftover !== 1;
43	};
44	
45	const componentGroupBase = (count: number): number => {
46	  const blocks = formsOneBlock(count) ? 1 : 0;
47	  const singles = count - blocks * BLOCK_SIZE;
48	  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_BASE_PREMIUM;
49	};
50	
51	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
52	
53	const mainItemBase = (item: Item): number =>
54	  MAIN_ITEM_BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
55	
56	const basePremium = (items: Item[]): number => {
57	  const componentCounts: Record<string, number> = {};
58	  let mainTotal = 0;
59	  for (const item of items) {
60	    if (isComponent(item)) {
61	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
62	    } else {
63	      mainTotal += mainItemBase(item);
64	    }
65	  }
66	  const componentTotal = Object.values(componentCounts).reduce(
67	    (sum, count) => sum + componentGroupBase(count),
68	    0
69	  );
70	  return mainTotal + componentTotal;
71	};
72	
73	const itemSurcharges = (items: Item[]): number => {
74	  let total = 0;
75	  for (const item of items) {
76	    if (isComponent(item)) continue;
77	    if (item.cursed) total += mainItemBase(item) * CURSED_SURCHARGE_RATE;
78	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
79	      total += mainItemBase(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE;
80	    }
81	  }
82	  return total;
83	};
84	
85	const roundUpToGold = (amount: number): number => {
86	  const precisionSafe = Math.round(amount * 100) / 100;
87	  return Math.ceil(precisionSafe);
88	};
89	
90	const LOYALTY_DISCOUNT_RATE = 0.2;
91	const LOYALTY_THRESHOLD_YEARS = 2;
92	const FOLLOWUP_DISCOUNT_RATE = 0.15;
93	
94	export type Damage = {
95	  itemType: string;
96	  amount: number;
97	};
98	
99	export type ClaimInput = {
100	  items: Item[];
101	  damages: Damage[];
102	  remainingCap?: number;
103	};
104	
105	export type ClaimResult = {
106	  payout: number;
107	  remainingCap: number;
108	};
109	
110	const DEDUCTIBLE = 100;
111	
112	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
113	const HIGH_ENCHANTMENT_CLAIM_RATE = 0.5;
114	
115	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
116	  sword: 1000,
117	  amulet: 600,
118	  staff: 800,
119	  potion: 400,
120	};
121	const COMPONENT_INSURANCE_VALUE = 250;
122	const CAP_MULTIPLIER = 2;
123	
124	const itemInsuranceValue = (item: Item): number => {
125	  if (isComponent(item)) return COMPONENT_INSURANCE_VALUE;
126	  return INSURANCE_VALUE_BY_TYPE[item.type] ?? 0;
127	};
128	
129	const insuranceSum = (items: Item[]): number =>
130	  items.reduce((sum, item) => sum + itemInsuranceValue(item), 0);
131	
132	export const claim = (input: ClaimInput): ClaimResult => {
133	  const payout = input.damages.reduce((sum, damage) => {
134	    const item = input.items.find((i) => i.type === damage.itemType);
135	    const baseAmount =
136	      item && (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
137	        ? damage.amount * HIGH_ENCHANTMENT_CLAIM_RATE
138	        : damage.amount;
139	    return sum + (baseAmount - DEDUCTIBLE);
140	  }, 0);
141	  const cap = input.remainingCap ?? insuranceSum(input.items) * CAP_MULTIPLIER;
142	  const finalPayout = Math.min(payout, cap);
143	  return { payout: finalPayout, remainingCap: cap - finalPayout };
144	};
145	
146	export const quote = (input: QuoteInput): number => {
147	  const base = basePremium(input.items);
148	  const surcharges = itemSurcharges(input.items);
149	  const firstInsurance = base * FIRST_INSURANCE_RATE;
150	  const loyaltyDiscount =
151	    input.customer.yearsInsured >= LOYALTY_THRESHOLD_YEARS
152	      ? base * LOYALTY_DISCOUNT_RATE
153	      : 0;
154	  const followupDiscount =
155	    input.customer.previousQuotes >= 1 ? base * FOLLOWUP_DISCOUNT_RATE : 0;
156	  const total =
157	    base +
158	    surcharges +
159	    firstInsurance -
160	    loyaltyDiscount -
161	    followupDiscount +
162	    PROCESSING_FEE;
163	  return roundUpToGold(total);
164	};
